function flatten(
  obj: Record<string, unknown>,
  prefix: string,
  ancestors: WeakSet<object>,
  result: Record<string, unknown>
): void {
  ancestors.add(obj);

  for (const [key, value] of Object.entries(obj)) {
    // Guard against keys that already contain dots — they survive as-is but
    // could collide with flattened paths; there is no lossless escape, so we
    // proceed and let the caller be aware.
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (ancestors.has(value)) {
        // Circular reference: storing undefined to mark the slot rather than
        // silently dropping it or infinite-looping.
        result[fullKey] = undefined;
        continue;
      }

      const nested = value as Record<string, unknown>;
      const keys = Object.keys(nested);

      if (keys.length === 0) {
        // Empty plain object: preserve as a leaf so the key is not silently lost.
        result[fullKey] = nested;
      } else {
        flatten(nested, fullKey, ancestors, result);
      }
    } else {
      // Scalars, arrays, Dates, RegExps, class instances, functions — all
      // treated as opaque leaves to avoid surprising recursive behaviour.
      result[fullKey] = value as Scalar | object;
    }
  }

  ancestors.delete(obj);
}

