      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      this.cache.delete(this.cache.keys().next().value!);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

type FlatRecord = Record<string, unknown>;

function isPlainObject(value: unknown): value is FlatRecord {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenRecursive(
  obj: FlatRecord,
  prefix: string,
  seen: WeakSet<object>,
  result: FlatRecord
): void {
  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix.length > 0 ? ` at key "${prefix}"` : ""}`
    );
  }

  seen.add(obj);

  for (const key of Object.keys(obj)) {
    // Guard against keys that could produce ambiguous dot-notation paths
    if (key.length === 0) {
      throw new Error("Empty string keys are not supported in flattenObject");
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      if (Object.keys(value).length === 0) {
        // Preserve empty plain objects as leaf values; no child keys to emit
        result[fullKey] = value;
      } else {
        flattenRecursive(value, fullKey, seen, result);
      }
    } else {
      // Arrays, Dates, RegExps, primitives, null, undefined → all leaf values
      result[fullKey] = value;
    }
  }

  // Remove after processing so shared (non-circular) references are allowed
  seen.delete(obj);
}

export default function flattenObject(obj: FlatRecord): FlatRecord {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatRecord = {};
  flattenRecursive(obj, "", new WeakSet(), result);
  return result;
}

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  // Sentinel head (MRU end) and tail (LRU end) to eliminate null-checks on boundary ops
  private readonly head: DLinkedNode<T>;
  private readonly tail: DLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinels — key/value are never read, only used for pointer wiring
    this.head = { key: "__HEAD__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__TAIL__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: DLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  // ── Private helpers ──────────────────────────────────────────────────────

  private insertAtFront(node: DLinkedNode<T>): void {
    node.prev = this.head;
    node.next = this.head.next;

    // head.next is always non-null (at minimum points to tail)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DLinkedNode<T>): void {
    // Both prev and next are always non-null for non-sentinel nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DLinkedNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Defensive: only evict if it's not the head sentinel (empty list guard)
    if (lru === null || lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

type PlainObject = { [key: string]: unknown };
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Reject Arrays, Dates, RegExps, Maps, Sets, class instances, etc.
  return proto === Object.prototype || proto === null;
}

function _flatten(
  obj: PlainObject,
  prefix: string,
  visited: WeakSet<object>,
  result: FlatObject
): void {
  // Guard against circular references BEFORE iterating children
  visited.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const path = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (
      isPlainObject(value) &&
      Object.keys(value).length > 0 && // empty objects become leaf values
      !visited.has(value)              // circular / shared-ref → treat as leaf
    ) {
      _flatten(value, path, visited, result);
    } else {
      result[path] = value;
    }
  }
}

function flattenObject(obj: unknown): FlatObject {
  // Reject non-plain-object inputs silently rather than throwing in the caller's face
  if (!isPlainObject(obj)) return {};
  const result: FlatObject = {};
  _flatten(obj, "", new WeakSet<object>(), result);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | Array<unknown>,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) return result;

  for (const [key, value] of Object.entries(obj)) {
    const dotKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, dotKey, result);
    } else {
      result[dotKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      this.map.delete(this.map.keys().next().value as string);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;
